22	    ///     マウスで地面をクリックしたときに発生するイベント
23	    /// </summary>
24	    public class CommonBlockPlaceSystem : IPlaceSystem
25	    {
26	        private const float PlaceableMaxDistance = 100f;
27	        private readonly IPlacementPreviewBlockGameObjectController _previewBlockController;
28	        private readonly ILocalPlayerInventory _localPlayerInventory;
29	        private readonly Camera _mainCamera;
30	        private readonly CommonBlockPlacePointCalculator _blockPlacePointCalculator;
31	        private readonly ElectricWireAutoConnectPreview _autoConnectPreview;
32	
33	        private BlockDirection _currentBlockDirection = BlockDirection.North;
34	        private Vector3Int? _clickStartPosition;
35	        private int _clickStartHeightOffset;
36	        private bool? _isStartZDirection;
37	        private List<PlaceInfo> _currentPlaceInfos = new();
38	        private BlockId? _previousSelectedBlockId;
39	
40	        private int _heightOffset;
41	
42	        public CommonBlockPlaceSystem(Camera mainCamera, IPlacementPreviewBlockGameObjectController previewBlockController, BlockGameObjectDataStore blockGameObjectDataStore, ILocalPlayerInventory localPlayerInventory)
43	        {
44	            _mainCamera = mainCamera;
45	            _previewBlockController = previewBlockController;
46	            _localPlayerInventory = localPlayerInventory;
47	            _blockPlacePointCalculator = new CommonBlockPlacePointCalculator(blockGameObjectDataStore);
48	            _autoConnectPreview = new ElectricWireAutoConnectPreview(mainCamera, blockGameObjectDataStore);
49	        }
50	        
51	        public void Enable()
52	        {
53	            _clickStartHeightOffset = -1;
54	        }
55	        public void Disable()
56	        {
57	            // デバッグモード時はプレビューを維持
58	            // Keep preview in debug mode
59	            if (!DebugParameters.GetValueOrDefaultBool(PlacePreviewKeepKey))
60	            {
61	                _previewBlockController.SetActive(false);
62	                _autoConnectPreview.Hide();
63	            }
64	
65	            // 連続設置状態をリセット
66	            _clickStartPosition = null;
67	            _isStartZDirection = null;
68	            _currentPlaceInfos.Clear();
69	        }
70	        
71	        public void ManualUpdate(PlaceSystemUpdateContext context)
72	        {
73	            UpdateHeightOffset();
74	            BlockDirectionControl();
75	            GroundClickControl(context);
76	            
77	            #region Internal
78	            
79	            void UpdateHeightOffset()
80	            {
81	                if (HybridInput.GetKeyDown(KeyCode.Q)) //TODO InputManagerに移す
82	                    _heightOffset--;
83	                else if (HybridInput.GetKeyDown(KeyCode.E)) _heightOffset++;
84	            }
85	            
86	            void BlockDirectionControl()
87	            {
88	                if (InputManager.Playable.BlockPlaceRotation.GetKeyDown)
89	                    // 東西南北の向きを変更する
90	                    _currentBlockDirection = _currentBlockDirection.HorizonRotation();
91	                
92	                //TODo シフトはインプットマネージャーに入れる
93	                if (HybridInput.GetKey(KeyCode.LeftShift) && InputManager.Playable.BlockPlaceRotation.GetKeyDown)
94	                    _currentBlockDirection = _currentBlockDirection.VerticalRotation();
95	            }
96	            
97	            #endregion
98	        }
99	        
100	        
101	        private void GroundClickControl(PlaceSystemUpdateContext context)
102	        {
103	            // ビルドメニューの選択ブロックが変わったら連続設置状態をリセット
104	            // Reset the continuous placement state when the build-menu selected block changes
105	            if (_previousSelectedBlockId != context.SelectedBlockId)
106	            {
107	                _clickStartPosition = null;
108	                _clickStartHeightOffset = _heightOffset;
109	            }
110	            _previousSelectedBlockId = context.SelectedBlockId;
111	
112	            //基本はプレビュー非表示
113	            _previewBlockController.SetActive(false);
114	
115	            // ブロック設置用のrayが当たっているか、当たっていたら設置位置を取得する
116	            var holdingBlockMaster = MasterHolder.BlockMaster.GetBlockMaster(context.SelectedBlockId.Value);
117	            if (!TryGetRayHitBlockPosition(_mainCamera, _heightOffset, _currentBlockDirection, holdingBlockMaster, out var placePoint, out var boundingBoxSurface)) { _autoConnectPreview.Hide(); return; }
118	
119	            // 設置可能な距離かどうか
120	            if (!IsBlockPlaceableDistance(PlaceableMaxDistance)) { _autoConnectPreview.Hide(); return; }
121	            
