19	        public static bool TryGetRayHitBlockPosition(Camera mainCamera, int heightOffset, BlockDirection currentBlockDirection, BlockMasterElement holdingBlock, out Vector3Int pos, out BlockPreviewBoundingBoxSurface surface)
20	        {
21	            pos = Vector3Int.zero;
22	            surface = null;
23	            
24	            if (!TryGetRayHitPosition(mainCamera, out var hitPos, out surface)) return false;
25	            
26	            pos = CalcPlacePoint(holdingBlock, hitPos, heightOffset, currentBlockDirection, surface);
27	            
28	            return true;
29	        }
30	        
31	        
32	        public static bool TryGetRayHitPosition(Camera mainCamera, out Vector3 pos, out BlockPreviewBoundingBoxSurface surface)
33	        {
34	            surface = null;
35	            pos = Vector3Int.zero;
36	            var ray = mainCamera.ScreenPointToRay(HybridInput.GetMousePosition());
37	            
38	            //画面からのrayが何かにヒットしているか
39	            if (!Physics.Raycast(ray, out var hit, float.PositiveInfinity, LayerConst.Without_Player_MapObject_Block_LayerMask)) return false;
40	            //そのrayが地面のオブジェクトかブロックのバウンディングボックスにヒットしてるか
41	            if (
42	                !hit.transform.TryGetComponent<GroundGameObject>(out _) &&
43	                !hit.transform.TryGetComponent(out surface)
44	            )
45	            {
46	                return false;
47	            }
48	            
49	            pos = hit.point;
50	            
51	            return true;
