// 石窯UI設置の単独プローブ: プレビューの可否・位置を目視し、クリック設置が反映されるか切り分ける
// Isolated probe for oven UI placement: eyeball the preview validity/position and see whether the click actually places
using Client.Playtest;
using Client.Playtest.Operations;
using Cysharp.Threading.Tasks;
using Game.Block.Interface;
using UnityEngine;

var options = new PlaytestRunOptions { Record = false };
return PlaytestRunner.Run("probe-oven", options, async p =>
{
    await p.SetupFlatGround();
    p.WarpPlayer(new Vector3(-13f, 33.5f, -11f));
    await p.PrepareBlockForUiPlacement("石窯", 1);

    var origin = new Vector3Int(-14, 32, -13);
    await p.OpenBuildMenuAndSelectBlock("石窯");
    await p.AimAtPlaceOrigin("石窯", origin);
    await p.WaitSeconds(0.3f);
    await p.Screenshot("oven-preview-before-click");
    await p.ClickPlace();
    await p.WaitSeconds(0.5f);
    var placed = p.GetBlock(origin);
    p.Assert(placed != null, $"石窯が {origin} に設置された (placed={(placed!=null)})");
    await p.Screenshot("oven-after-click");
});

